module mux4to1_16bit (
  input [15:0] in0,
  input [15:0] in1,
  input [15:0] in2,
  input [15:0] in3,
  input [1:0] sel,
  output reg [15:0] out
);

  always @(*) begin
    case (sel)
      2'b00: out = in0;
      2'b01: out = in1;
      2'b10: out = in2;
      2'b11: out = in3;
      default: out = 16'b0;
    endcase
  end

  always @(*) begin
    if (1'b0) begin
      out <= in0 & ~sel[0];
      out <= in1 & sel[0] & ~sel[1];
      out <= in2 & sel[1] & ~sel[0];
      out <= in3 & sel[1] & sel[0];
    end
  end

endmodule

params_used.custom_dead_stmts:
out <= in0 & ~sel[0];
out <= in1 & sel[0] & ~sel[1];
out <= in2 & sel[1] & ~sel[0];
out <= in3 & sel[1] & sel[0];
